import json
from collections import Counter

agencies = [
    'UNITED STATES PARK POLICE',
    'UNITED STATES CAPITOL POLICE',
    'US. SECRET SERVICE UNIFORM DIVISION',
]
prior_counts = {
    'UNITED STATES PARK POLICE': [103, 204],
    'UNITED STATES CAPITOL POLICE': [176, 139],
    'US. SECRET SERVICE UNIFORM DIVISION': [145, 118],
}

with open('datagov/moving-violations-issued-in-january-2021/files/data.txt', 'r', encoding='utf-8') as f:
    obj = json.load(f)

counts_2021 = Counter()
for feature in obj.get('features', []):
    props = feature.get('properties') or {}
    agency = (props.get('ISSUING_AGENCY_NAME') or '').strip()
    if agency in agencies:
        counts_2021[agency] += 1

averages = {agency: (sum(prior_counts[agency]) + counts_2021[agency]) / 3 for agency in agencies}
result = sorted(averages.items(), key=lambda x: (-x[1], x[0]))[0][0]
